  "floating-label-input": {
    name: "floating-label-input",
    description: "Material UI floating label input",
    type: "registry:component",
    files: [{
      path: "src/registry/ui/floating-label-input.tsx",
      content: "import * as React from \"react\";\n\nimport { cn } from \"@/lib/utils\";\nimport { Label } from \"@radix-ui/react-label\";\nimport { Input } from \"@/components/ui/input\";\n\nexport const FloatingLabel: React.FC<React.ComponentProps<typeof Label>> = ({\n  className,\n  ...props\n}) => {\n  return (\n    <Label\n      className={cn(\n        \"peer-has-focus:secondary absolute start-2 top-2 z-10 origin-[0] -translate-y-4 transform cursor-text px-2 text-sm text-gray-500 duration-300 peer-placeholder-shown:top-1/2 peer-placeholder-shown:-translate-y-1/2  peer-focus:-top-2 peer-focus:-translate-y-4 peer-focus:px-2 rtl:peer-focus:left-auto rtl:peer-focus:translate-x-1/4\",\n        className,\n      )}\n      {...props}\n    />\n  );\n};\n\nexport const FloatingInput: React.FC<\n  React.ComponentProps<\"input\"> & {\n    label: string;\n  }\n> = ({ id, label, className, ...props }) => {\n  return (\n    <div className=\"relative\">\n      <Input\n        id={id}\n        className={cn(\"peer bg-background\", className)}\n        placeholder=\" \"\n        {...props}\n      />\n      <FloatingLabel htmlFor={id}>{label}</FloatingLabel>\n    </div>\n  );\n};\n",
      type: "registry:component",
    }],
  },
